{
  "name": "LLM Price Calc",
  "description": "A real-time LLM API cost calculator fetching live pricing from OpenRouter to compare OpenAI, Google, Anthropic, and open-source models."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface OpenRouterModel {
  id: string;
  name: string;
  created: number;
  description: string;
  context_length: number;
  pricing: {
    prompt: string; // usually per token string
    completion: string; // usually per token string
    image: string;
    request: string;
  };
  top_provider: {
    context_length: number | null;
    max_completion_tokens: number | null;
    is_moderated: boolean;
  };
}

export interface UnifiedModelData {
  id: string;
  name: string;
  provider: string;
  inputPricePerMillion: number;
  outputPricePerMillion: number;
  contextWindow: number;
}

export interface CostCalculation {
  model: UnifiedModelData;
  inputCost: number;
  outputCost: number;
  totalCost: number;
}

export type SortField = 'name' | 'provider' | 'inputPrice' | 'outputPrice' | 'totalCost' | 'contextWindow';
export type SortOrder = 'asc' | 'desc';

export interface FilterState {
  search: string;
  providers: string[]; // specific providers selected
  maxInputPrice: number | null;
  maxOutputPrice: number | null;
}

import { OpenRouterModel, UnifiedModelData } from '../types';

const OPENROUTER_API_URL = 'https://openrouter.ai/api/v1/models';
const CACHE_KEY = 'llm_pricing_cache';
const CACHE_DURATION = 1000 * 60 * 60; // 1 hour

interface CacheData {
  timestamp: number;
  models: UnifiedModelData[];
}

const PROVIDER_MAPPING: Record<string, string> = {
  'openai': 'OpenAI',
  'anthropic': 'Anthropic',
  'google': 'Google',
  'meta': 'Meta',
  'mistral': 'Mistral',
  'cohere': 'Cohere',
  'perplexity': 'Perplexity',
  'microsoft': 'Microsoft',
  'amazon': 'Amazon',
  'deepseek': 'DeepSeek',
  'qwen': 'Qwen',
};

// Helper to determine provider from ID string if not explicitly clear
const guessProvider = (id: string, name: string): string => {
  const lowerId = id.toLowerCase();

  if (lowerId.startsWith('openai/')) return 'OpenAI';
  if (lowerId.startsWith('google/')) return 'Google';
  if (lowerId.startsWith('anthropic/')) return 'Anthropic';
  if (lowerId.startsWith('mistral')) return 'Mistral';
  if (lowerId.startsWith('meta-llama/')) return 'Meta';
  if (lowerId.startsWith('meta/')) return 'Meta';
  if (lowerId.startsWith('cohere/')) return 'Cohere';
  if (lowerId.startsWith('deepseek/')) return 'DeepSeek';
  if (lowerId.startsWith('qwen/')) return 'Alibaba';

  // Fallback: take the first part of the ID before the slash
  const parts = id.split('/');
  if (parts.length > 1) {
    const key = parts[0].toLowerCase();
    // Capitalize first letter
    return key.charAt(0).toUpperCase() + key.slice(1);
  }

  return 'Other';
};

export const fetchModels = async (): Promise<UnifiedModelData[]> => {
  // Check Cache
  const cached = localStorage.getItem(CACHE_KEY);
  if (cached) {
    const parsedCache: CacheData = JSON.parse(cached);
    if (Date.now() - parsedCache.timestamp < CACHE_DURATION) {
      console.log('Using cached pricing data');
      return parsedCache.models;
    }
  }

  try {
    console.log('Fetching fresh pricing data from OpenRouter...');
    const response = await fetch(OPENROUTER_API_URL);

    if (!response.ok) {
      throw new Error(`Failed to fetch models: ${response.statusText}`);
    }

    const json = await response.json();
    const rawModels: OpenRouterModel[] = json.data;

    const normalizedModels: UnifiedModelData[] = rawModels.map((model) => {
      // OpenRouter prices are per token. We want per Million.
      // Make sure to parse floating point correctly.
      const promptPrice = parseFloat(model.pricing.prompt) * 1_000_000;
      const completionPrice = parseFloat(model.pricing.completion) * 1_000_000;

      // Handle edge cases where price might be negative (shouldn't happen) or NaN
      const cleanPromptPrice = isNaN(promptPrice) ? 0 : Math.max(0, promptPrice);
      const cleanCompletionPrice = isNaN(completionPrice) ? 0 : Math.max(0, completionPrice);

      return {
        id: model.id,
        name: model.name,
        provider: guessProvider(model.id, model.name),
        inputPricePerMillion: cleanPromptPrice,
        outputPricePerMillion: cleanCompletionPrice,
        contextWindow: model.context_length || 0,
      };
    });

    // Save to cache
    const cacheData: CacheData = {
      timestamp: Date.now(),
      models: normalizedModels,
    };
    localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));

    return normalizedModels;

  } catch (error) {
    console.error("Error fetching pricing:", error);
    // If fetch fails but we have stale cache, return it
    if (cached) {
       console.warn("Returning stale cache due to fetch error");
       return JSON.parse(cached).models;
    }
    throw error;
  }
};

export const calculateModelCost = (
  model: UnifiedModelData, 
  inputTokens: number, 
  outputTokens: number
) => {
  // inputPricePerMillion is $/1M tokens. 
  // Formula: (tokens / 1,000,000) * price_per_million

  const inputCost = (inputTokens / 1_000_000) * model.inputPricePerMillion;
  const outputCost = (outputTokens / 1_000_000) * model.outputPricePerMillion;

  return {
    model,
    inputCost,
    outputCost,
    totalCost: inputCost + outputCost
  };
};

import React from 'react';
import { Database, MessageSquare } from 'lucide-react';

interface InputCardProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  icon: 'input' | 'output';
}

export const InputCard: React.FC<InputCardProps> = ({ label, value, onChange, icon }) => {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseInt(e.target.value.replace(/,/g, ''), 10);
    if (!isNaN(val)) {
      onChange(val);
    } else if (e.target.value === '') {
      onChange(0);
    }
  };

  const handleQuickSet = (amount: number) => {
    onChange(amount);
  };

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg">
      <div className="flex items-center gap-3 mb-4">
        <div className={`p-2 rounded-lg ${icon === 'input' ? 'bg-blue-500/10 text-blue-400' : 'bg-emerald-500/10 text-emerald-400'}`}>
          {icon === 'input' ? <Database size={20} /> : <MessageSquare size={20} />}
        </div>
        <h3 className="text-lg font-semibold text-slate-100">{label}</h3>
      </div>

      <div className="relative mb-4">
        <input
          type="text"
          value={value.toLocaleString()}
          onChange={handleChange}
          className="w-full bg-slate-900 border border-slate-600 text-slate-100 text-2xl font-mono p-4 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
        />
        <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 text-sm font-medium">
          TOKENS
        </span>
      </div>

      <div className="flex gap-2 flex-wrap">
        {[1000, 10000, 100000, 1000000].map((amt) => (
          <button
            key={amt}
            onClick={() => handleQuickSet(amt)}
            className="px-3 py-1 bg-slate-700 hover:bg-slate-600 text-slate-300 text-xs rounded-full transition-colors"
          >
            {amt >= 1000000 ? `${amt / 1000000}M` : `${amt / 1000}k`}
          </button>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  Cell
} from 'recharts';
import { CostCalculation } from '../types';

interface CostChartProps {
  data: CostCalculation[];
}

export const CostChart: React.FC<CostChartProps> = ({ data }) => {
  // Take top 10 most relevant models (cheapest? no, let's just take the first 10 of current sort)
  // Or perhaps the top 5 cheapest and top 5 most popular if we had popularity data.
  // For now, visualize the top 10 visible in the table.
  const chartData = data.slice(0, 15).map(item => ({
    name: item.model.name.split('/').pop() || item.model.name, // Shorten name
    input: item.inputCost,
    output: item.outputCost,
    total: item.totalCost,
    provider: item.model.provider
  }));

  if (chartData.length === 0) return null;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg h-[400px] flex flex-col">
      <h3 className="text-lg font-semibold text-slate-100 mb-6">Cost Breakdown (Top 15 Sorted)</h3>
      <div className="flex-1 w-full min-h-0">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={chartData}
            margin={{
              top: 5,
              right: 30,
              left: 20,
              bottom: 5,
            }}
          >
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis 
              dataKey="name" 
              stroke="#94a3b8" 
              tick={{ fontSize: 10 }} 
              interval={0}
              angle={-45}
              textAnchor="end"
              height={80}
            />
            <YAxis 
              stroke="#94a3b8" 
              tickFormatter={(val) => `$${val.toFixed(4)}`}
              width={70}
            />
            <Tooltip 
              contentStyle={{ backgroundColor: '#1e293b', borderColor: '#475569', color: '#f1f5f9' }}
              itemStyle={{ color: '#f1f5f9' }}
              formatter={(value: number) => [`$${value.toFixed(6)}`, 'Cost']}
              labelStyle={{ color: '#94a3b8', marginBottom: '0.5rem' }}
            />
            <Legend wrapperStyle={{ paddingTop: '10px' }}/>
            <Bar dataKey="input" name="Input Cost" stackId="a" fill="#3b82f6" />
            <Bar dataKey="output" name="Output Cost" stackId="a" fill="#10b981" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React from 'react';
import { CostCalculation, SortField, SortOrder } from '../types';
import { ArrowUpDown, ArrowUp, ArrowDown, ExternalLink, Info } from 'lucide-react';

interface ComparisonTableProps {
  data: CostCalculation[];
  sortField: SortField;
  sortOrder: SortOrder;
  onSort: (field: SortField) => void;
}

export const ComparisonTable: React.FC<ComparisonTableProps> = ({ 
  data, 
  sortField, 
  sortOrder, 
  onSort 
}) => {

  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <ArrowUpDown size={14} className="text-slate-500 opacity-50 group-hover:opacity-100" />;
    return sortOrder === 'asc' 
      ? <ArrowUp size={14} className="text-blue-400" />
      : <ArrowDown size={14} className="text-blue-400" />;
  };

  const HeaderCell = ({ field, label, align = 'right' }: { field: SortField, label: string, align?: 'left' | 'right' }) => (
    <th 
      className={`px-6 py-4 text-${align} text-xs font-medium text-slate-400 uppercase tracking-wider cursor-pointer group hover:bg-slate-700/50 transition-colors select-none sticky top-0 bg-slate-800 z-10`}
      onClick={() => onSort(field)}
    >
      <div className={`flex items-center gap-2 ${align === 'right' ? 'justify-end' : 'justify-start'}`}>
        {label}
        <SortIcon field={field} />
      </div>
    </th>
  );

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-lg overflow-hidden flex flex-col h-full">
      <div className="overflow-x-auto overflow-y-auto flex-1 custom-scrollbar">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="border-b border-slate-700">
              <HeaderCell field="name" label="Model" align="left" />
              <HeaderCell field="provider" label="Provider" align="left" />
              <HeaderCell field="contextWindow" label="Context" />
              <HeaderCell field="inputPrice" label="In ($/1M)" />
              <HeaderCell field="outputPrice" label="Out ($/1M)" />
              <HeaderCell field="totalCost" label="Total Cost" />
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50">
            {data.length === 0 ? (
               <tr>
                 <td colSpan={6} className="px-6 py-12 text-center text-slate-500">
                   No models found matching your filters.
                 </td>
               </tr>
            ) : (
              data.map((item) => (
                <tr key={item.model.id} className="hover:bg-slate-700/30 transition-colors group">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="text-sm font-medium text-slate-200">{item.model.name}</span>
                      <span className="text-xs text-slate-500 font-mono truncate max-w-[200px]" title={item.model.id}>{item.model.id}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-700 text-slate-300 border border-slate-600">
                      {item.model.provider}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm text-slate-400 font-mono">
                    {item.model.contextWindow > 0 ? (item.model.contextWindow / 1000).toFixed(0) + 'k' : '-'}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm text-slate-300 font-mono">
                    ${item.model.inputPricePerMillion.toFixed(2)}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm text-slate-300 font-mono">
                    ${item.model.outputPricePerMillion.toFixed(2)}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right bg-slate-700/10 group-hover:bg-slate-700/20">
                    <span className="text-emerald-400 font-bold font-mono text-sm">
                      ${item.totalCost.toFixed(6)}
                    </span>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
      <div className="px-6 py-3 bg-slate-900 border-t border-slate-700 text-xs text-slate-500 flex justify-between items-center">
        <span>Showing {data.length} models</span>
        <span className="flex items-center gap-1">
          <Info size={12} />
          Prices fetched from OpenRouter
        </span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  UnifiedModelData, 
  CostCalculation, 
  SortField, 
  SortOrder 
} from './types';
import { fetchModels, calculateModelCost } from './services/apiService';
import { InputCard } from './components/InputCard';
import { ComparisonTable } from './components/ComparisonTable';
import { CostChart } from './components/CostChart';
import { Search, Filter, RefreshCw, AlertTriangle } from 'lucide-react';

function App() {
  // State
  const [models, setModels] = useState<UnifiedModelData[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<number>(Date.now());

  // Input State
  const [inputTokens, setInputTokens] = useState<number>(100000);
  const [outputTokens, setOutputTokens] = useState<number>(20000);

  // Filter/Sort State
  const [search, setSearch] = useState('');
  const [selectedProvider, setSelectedProvider] = useState<string>('All');
  const [sortField, setSortField] = useState<SortField>('totalCost');
  const [sortOrder, setSortOrder] = useState<SortOrder>('asc');

  // Load Data
  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchModels();
      setModels(data);
      setLastUpdated(Date.now());
    } catch (err) {
      setError('Failed to fetch pricing data. Please check your connection.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Derived State: Providers List
  const providers = useMemo(() => {
    const p = new Set(models.map(m => m.provider));
    return ['All', ...Array.from(p).sort()];
  }, [models]);

  // Derived State: Calculated & Filtered Costs
  const calculatedData = useMemo(() => {
    // 1. Calculate
    let data: CostCalculation[] = models.map(model => 
      calculateModelCost(model, inputTokens, outputTokens)
    );

    // 2. Filter
    if (selectedProvider !== 'All') {
      data = data.filter(d => d.model.provider === selectedProvider);
    }

    if (search) {
      const q = search.toLowerCase();
      data = data.filter(d => 
        d.model.name.toLowerCase().includes(q) || 
        d.model.id.toLowerCase().includes(q)
      );
    }

    // 3. Sort
    data.sort((a, b) => {
      let valA: number | string;
      let valB: number | string;

      switch (sortField) {
        case 'name':
          valA = a.model.name;
          valB = b.model.name;
          break;
        case 'provider':
          valA = a.model.provider;
          valB = b.model.provider;
          break;
        case 'contextWindow':
          valA = a.model.contextWindow;
          valB = b.model.contextWindow;
          break;
        case 'inputPrice':
          valA = a.model.inputPricePerMillion;
          valB = b.model.inputPricePerMillion;
          break;
        case 'outputPrice':
          valA = a.model.outputPricePerMillion;
          valB = b.model.outputPricePerMillion;
          break;
        case 'totalCost':
        default:
          valA = a.totalCost;
          valB = b.totalCost;
      }

      if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
      if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
      return 0;
    });

    return data;
  }, [models, inputTokens, outputTokens, selectedProvider, search, sortField, sortOrder]);

  const handleSort = (field: SortField) => {
    if (field === sortField) {
      setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortOrder('asc'); // Default to cheapest/smallest first for new columns
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-blue-500/30">

      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-emerald-500 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shadow-blue-500/20">
              $
            </div>
            <h1 className="text-xl font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
              LLM Price Calc
            </h1>
          </div>

          <div className="flex items-center gap-4 text-sm text-slate-400">
            <span className="hidden sm:inline">Updated: {new Date(lastUpdated).toLocaleTimeString()}</span>
            <button 
              onClick={loadData}
              disabled={loading}
              className="p-2 hover:bg-slate-800 rounded-full transition-colors disabled:opacity-50"
              title="Refresh Prices"
            >
              <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">

        {/* Input Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InputCard 
            label="Input Tokens" 
            value={inputTokens} 
            onChange={setInputTokens}
            icon="input"
          />
          <InputCard 
            label="Output Tokens" 
            value={outputTokens} 
            onChange={setOutputTokens}
            icon="output"
          />
        </div>

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-lg flex items-center gap-2">
            <AlertTriangle size={18} />
            <span>{error}</span>
          </div>
        )}

        {/* Charts & Visuals */}
        {!loading && !error && (
          <CostChart data={calculatedData} />
        )}

        {/* Controls & Table */}
        <div className="space-y-4">

          {/* Filters */}
          <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-slate-900/50 p-4 rounded-xl border border-slate-800">
            <div className="flex items-center gap-4 w-full sm:w-auto">
              <div className="relative flex-1 sm:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                <input 
                  type="text" 
                  placeholder="Search models..." 
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-9 pr-4 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                />
              </div>

              <div className="relative">
                <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                <select 
                  value={selectedProvider}
                  onChange={(e) => setSelectedProvider(e.target.value)}
                  className="bg-slate-800 border border-slate-700 rounded-lg pl-9 pr-8 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
                >
                  {providers.map(p => (
                    <option key={p} value={p}>{p}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="text-sm text-slate-500">
              Sorted by <span className="text-slate-300 font-medium">{sortField === 'inputPrice' ? 'input price' : sortField === 'outputPrice' ? 'output price' : sortField === 'totalCost' ? 'total cost' : sortField}</span>
            </div>
          </div>

          {/* Table */}
          <div className="h-[600px]">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-500 gap-4">
                <RefreshCw size={32} className="animate-spin text-blue-500" />
                <p>Fetching latest pricing from OpenRouter...</p>
              </div>
            ) : (
              <ComparisonTable 
                data={calculatedData}
                sortField={sortField}
                sortOrder={sortOrder}
                onSort={handleSort}
              />
            )}
          </div>
        </div>

      </main>
    </div>
  );
}

export default App;

import { OpenRouterModel, UnifiedModelData } from '../types';

const OPENROUTER_API_URL = 'https://openrouter.ai/api/v1/models';
const CACHE_KEY = 'llm_pricing_cache_v2'; // Version bump to clear stale data
const CACHE_DURATION = 1000 * 60 * 60; // 1 hour

interface CacheData {
  timestamp: number;
  models: UnifiedModelData[];
}

const guessProvider = (id: string, name: string): string => {
  const lowerId = id.toLowerCase();

  if (lowerId.startsWith('openai/')) return 'OpenAI';
  if (lowerId.startsWith('google/')) return 'Google';
  if (lowerId.startsWith('anthropic/')) return 'Anthropic';
  if (lowerId.startsWith('mistral')) return 'Mistral';
  if (lowerId.startsWith('meta-llama/')) return 'Meta';
  if (lowerId.startsWith('meta/')) return 'Meta';
  if (lowerId.startsWith('cohere/')) return 'Cohere';
  if (lowerId.startsWith('deepseek/')) return 'DeepSeek';
  if (lowerId.startsWith('qwen/')) return 'Alibaba';
  if (lowerId.startsWith('microsoft/')) return 'Microsoft';
  if (lowerId.startsWith('perplexity/')) return 'Perplexity';

  // Fallback: take the first part of the ID before the slash
  const parts = id.split('/');
  if (parts.length > 1) {
    const key = parts[0].toLowerCase();
    // Capitalize first letter
    return key.charAt(0).toUpperCase() + key.slice(1);
  }

  return 'Other';
};

// Robust helper to parse price strings/numbers
const parsePrice = (value: string | number | undefined | null): number => {
  if (value === undefined || value === null) return 0;
  // Convert to string then parse to handle both number and string types from API
  const parsed = parseFloat(String(value));
  if (isNaN(parsed)) return 0;
  // Filter out negative pricing (sometimes used for unknown prices)
  return Math.max(0, parsed);
};

export const fetchModels = async (): Promise<UnifiedModelData[]> => {
  // Check Cache
  const cached = localStorage.getItem(CACHE_KEY);
  if (cached) {
    try {
      const parsedCache: CacheData = JSON.parse(cached);
      if (Date.now() - parsedCache.timestamp < CACHE_DURATION) {
        console.log('Using cached pricing data');
        return parsedCache.models;
      }
    } catch (e) {
      console.warn("Invalid cache data, clearing");
      localStorage.removeItem(CACHE_KEY);
    }
  }

  try {
    console.log('Fetching fresh pricing data from OpenRouter...');
    const response = await fetch(OPENROUTER_API_URL);

    if (!response.ok) {
      throw new Error(`Failed to fetch models: ${response.statusText}`);
    }

    const json = await response.json();
    const rawModels: OpenRouterModel[] = json.data;

    if (!Array.isArray(rawModels)) {
      throw new Error("Invalid API response structure: data is not an array");
    }

    const normalizedModels: UnifiedModelData[] = rawModels.map((model) => {
      const pricing = model.pricing || {};

      // Parse pricing - usually strings like "0.000005"
      // We accept strings or numbers and handle missing fields gracefully
      const promptPrice = parsePrice(pricing.prompt);
      const completionPrice = parsePrice(pricing.completion);

      return {
        id: model.id,
        name: model.name,
        provider: guessProvider(model.id, model.name),
        // Convert per-token price to per-million (price * 1,000,000)
        inputPricePerMillion: promptPrice * 1_000_000,
        outputPricePerMillion: completionPrice * 1_000_000,
        contextWindow: model.context_length || 0,
      };
    });

    // Save to cache
    const cacheData: CacheData = {
      timestamp: Date.now(),
      models: normalizedModels,
    };
    localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));

    return normalizedModels;

  } catch (error) {
    console.error("Error fetching pricing:", error);
    // If fetch fails but we have stale cache (even if expired), try to return it
    if (cached) {
       console.warn("Returning stale cache due to fetch error");
       try {
         return JSON.parse(cached).models;
       } catch (e) { /* ignore */ }
    }
    throw error;
  }
};

export const calculateModelCost = (
  model: UnifiedModelData, 
  inputTokens: number, 
  outputTokens: number
) => {
  // inputPricePerMillion is $/1M tokens. 
  // Formula: (tokens / 1,000,000) * price_per_million

  const inputCost = (inputTokens / 1_000_000) * model.inputPricePerMillion;
  const outputCost = (outputTokens / 1_000_000) * model.outputPricePerMillion;

  return {
    model,
    inputCost,
    outputCost,
    totalCost: inputCost + outputCost
  };
};

import { OpenRouterModel, UnifiedModelData } from '../types';

const OPENROUTER_API_URL = 'https://openrouter.ai/api/v1/models';
const CACHE_KEY = 'llm_pricing_cache_v2'; // Version bump to clear stale data
const CACHE_DURATION = 1000 * 60 * 60; // 1 hour

interface CacheData {
  timestamp: number;
  models: UnifiedModelData[];
}

const guessProvider = (id: string, name: string): string => {
  const lowerId = id.toLowerCase();

  if (lowerId.startsWith('openai/')) return 'OpenAI';
  if (lowerId.startsWith('google/')) return 'Google';
  if (lowerId.startsWith('anthropic/')) return 'Anthropic';
  if (lowerId.startsWith('mistral')) return 'Mistral';
  if (lowerId.startsWith('meta-llama/')) return 'Meta';
  if (lowerId.startsWith('meta/')) return 'Meta';
  if (lowerId.startsWith('cohere/')) return 'Cohere';
  if (lowerId.startsWith('deepseek/')) return 'DeepSeek';
  if (lowerId.startsWith('qwen/')) return 'Alibaba';
  if (lowerId.startsWith('microsoft/')) return 'Microsoft';
  if (lowerId.startsWith('perplexity/')) return 'Perplexity';

  // Fallback: take the first part of the ID before the slash
  const parts = id.split('/');
  if (parts.length > 1) {
    const key = parts[0].toLowerCase();
    // Capitalize first letter
    return key.charAt(0).toUpperCase() + key.slice(1);
  }

  return 'Other';
};

