export const CostChart: React.FC<CostChartProps> = ({ data }) => {
  // Take top 15 visible in the table.
  const chartData = data.slice(0, 15).map(item => ({
    name: item.model.name.split('/').pop() || item.model.name, // Shorten name
    input: item.inputCost,
    output: item.outputCost,
    total: item.totalCost,
    provider: item.model.provider
  }));

  if (chartData.length === 0) return null;

  // Check if all visible items are free (total cost 0).
  // If so, the chart would look empty/broken, so we show a message instead.
  const isAllFree = chartData.every(item => item.total === 0);

  if (isAllFree) {
    return (
      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg h-[400px] flex flex-col items-center justify-center text-center">
