  if (isSelectionMode) {
    // Selection Mode: Show EXACTLY what was passed, no filtering of free models, no slicing.
    chartData = data.map(item => ({
      name: item.model.name.split('/').pop() || item.model.name, // Shorten name
      fullName: item.model.name,
      input: item.inputCost * rate,
      output: item.outputCost * rate,
      total: item.totalCost * rate,
      provider: item.model.provider
    }));
  } else {
    // Default Mode: Filter out free models (totalCost > 0) AND take the top 15
    chartData = data
      .filter(item => item.totalCost > 0)
      .slice(0, 15)
      .map(item => ({
        name: item.model.name.split('/').pop() || item.model.name, // Shorten name
        fullName: item.model.name,
        input: item.inputCost * rate,
        output: item.outputCost * rate,
        total: item.totalCost * rate,
        provider: item.model.provider
      }));
  }

  // Custom label renderer for the total cost above the bar
  const renderCustomLabel = (props: any) => {
    const { x, y, width, payload } = props;

    // Safety check: ensure payload exists before accessing properties
    if (!payload) return null;

    const value = payload.total;

    // Avoid rendering if value is 0 or invalid
    if (value === undefined || value === null) return null;

    return (
      <text 
        x={x + width / 2} 
        y={y - 8} 
        fill="#cbd5e1" // text-slate-300
        textAnchor="middle" 
        fontSize={11}
        fontWeight={500}
        className="font-mono"
      >
        {symbol}{value.toFixed(currency === 'INR' ? 2 : 4)}
      </text>
    );
  };

  if (chartData.length === 0) {
    return (
      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg h-[400px] flex flex-col items-center justify-center text-center">
        <h3 className="text-lg font-semibold text-slate-100 mb-2">Cost Breakdown</h3>
        <p className="text-slate-400 mb-1">
          {isSelectionMode ? "No models selected." : "No paid models currently visible."}
        </p>
        <p className="text-slate-500 text-sm">
          {isSelectionMode ? "Select models from the list below to compare." : "Adjust filters or select paid models to see the cost comparison."}
        </p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg h-[400px] flex flex-col">
      <h3 className="text-lg font-semibold text-slate-100 mb-6">
        Cost Breakdown 
        <span className="text-slate-500 font-normal text-base ml-2">
          ({isSelectionMode ? `Selected ${chartData.length}` : `Top ${chartData.length} Paid`})
        </span>
      </h3>
      <div className="flex-1 w-full min-h-0">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={chartData}
            margin={{
              top: 25, // Increased top margin to accommodate labels
              right: 30,
              left: 20,
              bottom: 20, 
            }}
          >
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis 
              dataKey="name" 
              stroke="#94a3b8" 
              tick={{ fontSize: 10 }} 
              interval={0}
              angle={-45}
              textAnchor="end"
              height={100} 
            />
            <YAxis 
              stroke="#94a3b8" 
              tickFormatter={(val) => `${symbol}${val.toFixed(currency === 'INR' ? 2 : 4)}`}
              width={70}
            />
            <Tooltip 
              content={<CustomTooltip symbol={symbol} />}
              cursor={{ fill: '#334155', opacity: 0.2 }}
            />
            <Legend wrapperStyle={{ paddingTop: '10px' }}/>
            <Bar dataKey="input" name="Input Cost" stackId="a" fill="#3b82f6" />
            <Bar 
              dataKey="output" 
              name="Output Cost" 
              stackId="a" 
              fill="#10b981" 
              label={renderCustomLabel}
            />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React from 'react';
import { Database, MessageSquare } from 'lucide-react';

interface InputCardProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  icon: 'input' | 'output';
  children?: React.ReactNode;
}

export const InputCard: React.FC<InputCardProps> = ({ label, value, onChange, icon, children }) => {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseInt(e.target.value.replace(/,/g, ''), 10);
    if (!isNaN(val)) {
      onChange(val);
    } else if (e.target.value === '') {
      onChange(0);
    }
  };

  const handleQuickSet = (amount: number) => {
    onChange(amount);
  };

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg flex flex-col h-full">
      <div className="flex items-center gap-3 mb-4">
        <div className={`p-2 rounded-lg ${icon === 'input' ? 'bg-blue-500/10 text-blue-400' : 'bg-emerald-500/10 text-emerald-400'}`}>
          {icon === 'input' ? <Database size={20} /> : <MessageSquare size={20} />}
        </div>
        <h3 className="text-lg font-semibold text-slate-100">{label}</h3>
      </div>

      <div className="relative mb-4">
        <input
          type="text"
          value={value.toLocaleString()}
          onChange={handleChange}
          className="w-full bg-slate-900 border border-slate-600 text-slate-100 text-2xl font-mono p-4 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
        />
        <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 text-sm font-medium">
          TOKENS
        </span>
      </div>

      <div className="flex gap-2 flex-wrap mb-auto">
        {[1000, 10000, 100000, 1000000].map((amt) => (
          <button
            key={amt}
            onClick={() => handleQuickSet(amt)}
            className="px-3 py-1 bg-slate-700 hover:bg-slate-600 text-slate-300 text-xs rounded-full transition-colors"
          >
            {amt >= 1000000 ? `${amt / 1000000}M` : `${amt / 1000}k`}
